# GraphQL Types

class UserType(graphene.ObjectType):
    id = graphene.ID(required=True)
    username = graphene.String(required=True)
    email = graphene.String(required=True)
    display_name = graphene.String()
    joined_at = graphene.DateTime()
    reviews = graphene.List(lambda: ReviewType)
    review_count = graphene.Int()

    def resolve_reviews(self, info):
        return [r for r in REVIEWS if r["user_id"] == self.id]

    def resolve_review_count(self, info):
        return len([r for r in REVIEWS if r["user_id"] == self.id])


class ReviewType(graphene.ObjectType):
    id = graphene.ID(required=True)
    product_id = graphene.ID(required=True)
    user_id = graphene.ID(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String()
    comment = graphene.String()
    created_at = graphene.DateTime()
    updated_at = graphene.DateTime()
    verified_purchase = graphene.Boolean()
    helpful_count = graphene.Int()
    user = graphene.Field(UserType)
    product = graphene.Field(lambda: ProductType)

    def resolve_user(self, info):
        user_data = next((u for u in USERS if u["id"] == self.user_id), None)
        if user_data:
            return UserType(**user_data)
        return None

    def resolve_product(self, info):
        product_data = next((p for p in PRODUCTS if p["id"] == self.product_id), None)
        if product_data:
            return ProductType(**product_data)
        return None


class CategoryType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    slug = graphene.String(required=True)
    parent_id = graphene.ID()
    parent = graphene.Field(lambda: CategoryType)
    subcategories = graphene.List(lambda: CategoryType)
    products = graphene.List(lambda: ProductType, active_only=graphene.Boolean(default_value=True))
    product_count = graphene.Int(active_only=graphene.Boolean(default_value=True))

    def resolve_parent(self, info):
        if self.parent_id:
            parent_data = next((c for c in CATEGORIES if c["id"] == self.parent_id), None)
            if parent_data:
                return CategoryType(**parent_data)
        return None

    def resolve_subcategories(self, info):
        return [CategoryType(**c) for c in CATEGORIES if c["parent_id"] == self.id]

    def resolve_products(self, info, active_only=True):
        products = [p for p in PRODUCTS if p["category_id"] == self.id]
        if active_only:
            products = [p for p in products if p["is_active"]]
        return [ProductType(**p) for p in products]

    def resolve_product_count(self, info, active_only=True):
        products = [p for p in PRODUCTS if p["category_id"] == self.id]
        if active_only:
            products = [p for p in products if p["is_active"]]
        return len(products)


class ProductType(graphene.ObjectType):
    id = graphene.ID(required=True)
    name = graphene.String(required=True)
    description = graphene.String()
    price = graphene.Float(required=True)
    sku = graphene.String(required=True)
    stock_quantity = graphene.Int()
    category_id = graphene.ID(required=True)
    is_active = graphene.Boolean()
    created_at = graphene.DateTime()
    updated_at = graphene.DateTime()
    image_url = graphene.String()
    weight = graphene.Float()
    brand = graphene.String()
    in_stock = graphene.Boolean()
    category = graphene.Field(CategoryType)
    reviews = graphene.List(ReviewType, rating=graphene.Int(), verified_only=graphene.Boolean(default_value=False))
    review_count = graphene.Int()
    average_rating = graphene.Float()

    def resolve_in_stock(self, info):
        return self.stock_quantity > 0 if self.stock_quantity is not None else False

    def resolve_category(self, info):
        cat_data = next((c for c in CATEGORIES if c["id"] == self.category_id), None)
        if cat_data:
            return CategoryType(**cat_data)
        return None

    def resolve_reviews(self, info, rating=None, verified_only=False):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self.id]
        if rating is not None:
            product_reviews = [r for r in product_reviews if r["rating"] == rating]
        if verified_only:
            product_reviews = [r for r in product_reviews if r["verified_purchase"]]
        return [ReviewType(**r) for r in product_reviews]

    def resolve_review_count(self, info):
        return len([r for r in REVIEWS if r["product_id"] == self.id])

    def resolve_average_rating(self, info):
        product_reviews = [r for r in REVIEWS if r["product_id"] == self.id]
        if not product_reviews:
            return None
        return sum(r["rating"] for r in product_reviews) / len(product_reviews)


class PriceRangeInput(graphene.InputObjectType):
    min_price = graphene.Float()
    max_price = graphene.Float()


class ProductSortEnum(graphene.Enum):
    PRICE_ASC = "price_asc"
    PRICE_DESC = "price_desc"
    NAME_ASC = "name_asc"
    NAME_DESC = "name_desc"
    NEWEST = "newest"
    RATING = "rating"


class ProductConnection(graphene.ObjectType):
    items = graphene.List(ProductType, required=True)
    total_count = graphene.Int(required=True)
    has_next_page = graphene.Boolean(required=True)
    has_previous_page = graphene.Boolean(required=True)


class ReviewConnection(graphene.ObjectType):
    items = graphene.List(ReviewType, required=True)
    total_count = graphene.Int(required=True)
    average_rating = graphene.Float()


class CatalogStats(graphene.ObjectType):
    total_products = graphene.Int()
    active_products = graphene.Int()
    total_categories = graphene.Int()
    total_reviews = graphene.Int()
    average_product_price = graphene.Float()
    average_review_rating = graphene.Float()


# Queries

class Query(graphene.ObjectType):
    # Product queries
    product = graphene.Field(
        ProductType,
        id=graphene.ID(required=True),
        description="Fetch a single product by ID"
    )
    product_by_sku = graphene.Field(
        ProductType,
        sku=graphene.String(required=True),
        description="Fetch a single product by SKU"
    )
    products = graphene.Field(
        ProductConnection,
        category_id=graphene.ID(),
        search=graphene.String(),
        brand=graphene.String(),
        price_range=PriceRangeInput(),
        in_stock_only=graphene.Boolean(default_value=False),
        active_only=graphene.Boolean(default_value=True),
        sort_by=ProductSortEnum(),
        limit=graphene.Int(default_value=20),
        offset=graphene.Int(default_value=0),
        description="Fetch products with filtering, sorting, and pagination"
    )

    # Category queries
    category = graphene.Field(
        CategoryType,
        id=graphene.ID(),
        slug=graphene.String(),
        description="Fetch a single category by ID or slug"
    )
    categories = graphene.List(
        CategoryType,
        top_level_only=graphene.Boolean(default_value=False),
        description="Fetch all categories, optionally only top-level ones"
    )

    # Review queries
    review = graphene.Field(
        ReviewType,
        id=graphene.ID(required=True),
        description="Fetch a single review by ID"
    )
    reviews = graphene.Field(
        ReviewConnection,
        product_id=graphene.ID(),
        user_id=graphene.ID(),
        min_rating=graphene.Int(),
        max_rating=graphene.Int(),
        verified_only=graphene.Boolean(default_value=False),
        sort_by_helpful=graphene.Boolean(default_value=False),
        limit=graphene.Int(default_value=20),
        offset=graphene.Int(default_value=0),
        description="Fetch reviews with filtering and pagination"
    )

    # User queries
    user = graphene.Field(
        UserType,
        id=graphene.ID(),
        username=graphene.String(),
        description="Fetch a user by ID or username"
    )

    # Stats
    catalog_stats = graphene.Field(
        CatalogStats,
        description="Get overall catalog statistics"
    )

    # Product resolvers
    def resolve_product(self, info, id):
        product_data = next((p for p in PRODUCTS if p["id"] == id), None)
        if product_data:
            return ProductType(**product_data)
        return None

    def resolve_product_by_sku(self, info, sku):
        product_data = next((p for p in PRODUCTS if p["sku"] == sku), None)
        if product_data:
            return ProductType(**product_data)
        return None

    def resolve_products(self, info, category_id=None, search=None, brand=None,
                         price_range=None, in_stock_only=False, active_only=True,
                         sort_by=None, limit=20, offset=0):
        filtered = list(PRODUCTS)

        if active_only:
            filtered = [p for p in filtered if p["is_active"]]

        if category_id:
            # Include products from subcategories too
            category_ids = {category_id}
            for cat in CATEGORIES:
                if cat["parent_id"] == category_id:
                    category_ids.add(cat["id"])
            filtered = [p for p in filtered if p["category_id"] in category_ids]

        if search:
            search_lower = search.lower()
            filtered = [p for p in filtered if
                        search_lower in p["name"].lower() or
                        search_lower in p["description"].lower() or
                        search_lower in p.get("brand", "").lower()]

        if brand:
            filtered = [p for p in filtered if p.get("brand", "").lower() == brand.lower()]

        if price_range:
            if price_range.min_price is not None:
                filtered = [p for p in filtered if p["price"] >= price_range.min_price]
            if price_range.max_price is not None:
                filtered = [p for p in filtered if p["price"] <= price_range.max_price]

        if in_stock_only:
            filtered = [p for p in filtered if p["stock_quantity"] > 0]

        # Sorting
        if sort_by:
            if sort_by == ProductSortEnum.PRICE_ASC:
                filtered.sort(key=lambda p: p["price"])
            elif sort_by == ProductSortEnum.PRICE_DESC:
                filtered.sort(key=lambda p: p["price"], reverse=True)
            elif sort_by == ProductSortEnum.NAME_ASC:
                filtered.sort(key=lambda p: p["name"].lower())
            elif sort_by == ProductSortEnum.NAME_DESC:
                filtered.sort(key=lambda p: p["name"].lower(), reverse=True)
            elif sort_by == ProductSortEnum.NEWEST:
                filtered.sort(key=lambda p: p["created_at"], reverse=True)
            elif sort_by == ProductSortEnum.RATING:
                def avg_rating(product):
                    product_reviews = [r for r in REVIEWS if r["product_id"] == product["id"]]
                    if not product_reviews:
                        return 0
                    return sum(r["rating"] for r in product_reviews) / len(product_reviews)
                filtered.sort(key=avg_rating, reverse=True)

        total_count = len(filtered)
        paginated = filtered[offset:offset + limit]

        return ProductConnection(
            items=[ProductType(**p) for p in paginated],
            total_count=total_count,
            has_next_page=(offset + limit) < total_count,
            has_previous_page=offset > 0
        )

    # Category resolvers
    def resolve_category(self, info, id=None, slug=None):
        if id:
            cat_data = next((c for c in CATEGORIES if c["id"] == id), None)
        elif slug:
            cat_data = next((c for c in CATEGORIES if c["slug"] == slug), None)
        else:
            return None

        if cat_data:
            return CategoryType(**cat_data)
        return None

    def resolve_categories(self, info, top_level_only=False):
        cats = CATEGORIES
        if top_level_only:
            cats = [c for c in cats if c["parent_id"] is None]
        return [CategoryType(**c) for c in cats]

    # Review resolvers
    def resolve_review(self, info, id):
        review_data = next((r for r in REVIEWS if r["id"] == id), None)
        if review_data:
            return ReviewType(**review_data)
        return None

    def resolve_reviews(self, info, product_id=None, user_id=None,
                        min_rating=None, max_rating=None, verified_only=False,
                        sort_by_helpful=False, limit=20, offset=0):
        filtered = list(REVIEWS)

        if product_id:
            filtered = [r for r in filtered if r["product_id"] == product_id]

        if user_id:
            filtered = [r for r in filtered if r["user_id"] == user_id]

        if min_rating is not None:
            filtered = [r for r in filtered if r["rating"] >= min_rating]

        if max_rating is not None:
            filtered = [r for r in filtered if r["rating"] <= max_rating]

        if verified_only:
            filtered = [r for r in filtered if r["verified_purchase"]]

        if sort_by_helpful:
            filtered.sort(key=lambda r: r["helpful_count"], reverse=True)
        else:
            filtered.sort(key=lambda r: r["created_at"], reverse=True)

        total_count = len(filtered)
        avg = None
        if filtered:
            avg = sum(r["rating"] for r in filtered) / len(filtered)

        paginated = filtered[offset:offset + limit]

        return ReviewConnection(
            items=[ReviewType(**r) for r in paginated],
            total_count=total_count,
            average_rating=avg
        )

    # User resolver
    def resolve_user(self, info, id=None, username=None):
        if id:
            user_data = next((u for u in USERS if u["id"] == id), None)
        elif username:
            user_data = next((u for u in USERS if u["username"] == username), None)
        else:
            return None

        if user_data:
            return UserType(**user_data)
        return None

    # Stats resolver
    def resolve_catalog_stats(self, info):
        active = [p for p in PRODUCTS if p["is_active"]]
        all_ratings = [r["rating"] for r in REVIEWS]
        all_prices = [p["price"] for p in PRODUCTS]

        return CatalogStats(
            total_products=len(PRODUCTS),
            active_products=len(active),
            total_categories=len(CATEGORIES),
            total_reviews=len(REVIEWS),
            average_product_price=sum(all_prices) / len(all_prices) if all_prices else 0,
            average_review_rating=sum(all_ratings) / len(all_ratings) if all_ratings else 0
        )


# Mutations

class CreateReviewInput(graphene.InputObjectType):
    product_id = graphene.ID(required=True)
    user_id = graphene.ID(required=True)
    rating = graphene.Int(required=True)
    title = graphene.String()
    comment = graphene.String()
    verified_purchase = graphene.Boolean(default_value=False)


class CreateReview(graphene.Mutation):
    class Arguments:
        input = CreateReviewInput(required=True)

    review = graphene.Field(ReviewType)
    ok = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, input):
        # Validate rating
        if input.rating < 1 or input.rating > 5:
            return CreateReview(review=None, ok=False, message="Rating must be between 1 and 5")

        # Validate product exists
        product = next((p for p in PRODUCTS if p["id"] == input.product_id), None)
        if not product:
            return CreateReview(review=None, ok=False, message="Product not found")

        # Validate user exists
        user = next((u for u in USERS if u["id"] == input.user_id), None)
        if not user:
            return CreateReview(review=None, ok=False, message="User not found")

        # Check for duplicate review
        existing = next((r for r in REVIEWS if r["product_id"] == input.product_id and r["user_id"] == input.user_id), None)
        if existing:
            return CreateReview(review=None, ok=False, message="User has already reviewed this product")

        now = datetime.utcnow().isoformat()
        new_id = str(max(int(r["id"]) for r in REVIEWS) + 1)

        new_review = {
            "id": new_id,
            "product_id": input.product_id,
            "user_id": input.user_id,
            "rating": input.rating,
            "title": input.title or "",
            "comment": input.comment or "",
            "created_at": now,
            "updated_at": now,
            "verified_purchase": input.verified_purchase,
            "helpful_count": 0,
        }

        REVIEWS.append(new_review)
        return CreateReview(review=ReviewType(**new_review), ok=True, message="Review created successfully")


class UpdateReviewInput(graphene.InputObjectType):
    rating = graphene.Int()
    title = graphene.String()
    comment = graphene.String()


class UpdateReview(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)
        input = UpdateReviewInput(required=True)

    review = graphene.Field(ReviewType)
    ok = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, id, input):
        review = next((r for r in REVIEWS if r["id"] == id), None)
        if not review:
            return UpdateReview(review=None, ok=False, message="Review not found")

        if input.rating is not None:
            if input.rating < 1 or input.rating > 5:
                return UpdateReview(review=None, ok=False, message="Rating must be between 1 and 5")
            review["rating"] = input.rating

        if input.title is not None:
            review["title"] = input.title

        if input.comment is not None:
            review["comment"] = input.comment

        review["updated_at"] = datetime.utcnow().isoformat()

        return UpdateReview(review=ReviewType(**review), ok=True, message="Review updated successfully")


class DeleteReview(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)

    ok = graphene.Boolean()
    message = graphene.String()

    def mutate(self, info, id):
        review = next((r for r in REVIEWS if r["id"] == id), None)
        if not review:
            return DeleteReview(ok=False, message="Review not found")

        REVIEWS.remove(review)
        return DeleteReview(ok=True, message="Review deleted successfully")


class MarkReviewHelpful(graphene.Mutation):
    class Arguments:
        id = graphene.ID(required=True)

    review = graphene.Field(ReviewType)
    ok = graphene.Boolean()

    def mutate(self, info, id):
        review = next((r for r in REVIEWS if r["id"] == id), None)
        if not review:
            return MarkReviewHelpful(review=None, ok=False)

        review["helpful_count"] = review.get("helpful_count", 0) + 1
        return MarkReviewHelpful(review=ReviewType(**review), ok=True)


class Mutation(graphene.ObjectType):
    create_review = CreateReview.Field(description="Create a new product review")
    update_review = UpdateReview.Field(description="Update an existing review")
    delete_review = DeleteReview.Field(description="Delete a review")
    mark_review_helpful = MarkReviewHelpful.Field(description="Mark a review as helpful (increment counter)")


# Schema
schema = graphene.Schema(query=Query, mutation=Mutation)

